using System;

class Program
{
    static void Main(string[] args)
    {
        int number = 42;
        string message = "C# öyrənmək əyləncəlidir!";

        if (number > 0)
        {
            Console.WriteLine($"{message} Sayı: {number}");
        }
        else
        {
            Console.WriteLine("Sayı sıfırdan kiçik və ya bərabərdir.");
        }
    }
}
// Output:
// C# öyrənmək əyləncəlidir! Sayı: 42

using System;

class Program
{
    static void Main(string[] args)
    {
        int[] numbers = {1, 2, 3, 4, 5};
        int sum = 0;

        for (int i = 0; i < numbers.Length; i++)
        {
            sum += numbers[i];
        }

        Console.WriteLine($"Cəm: {sum}");
    }
}
// Output:
// Cəm: 15

